constraint_parent_max_20_children_fixed.cmd:
cd $PROJECT_ROOT && python3 << 'PYEOF'
import json
with open('prep/superset.k.json') as f:
    data = json.load(f)
parent_children = {}
for section in data.get('children', {}).values():
    for question in section.get('children', {}).values():
        tags = question.get('metadata', {}).get('tags', '')
        if tags:
            for tag in tags.split(','):
                tag = tag.strip()
                if '/' in tag:
                    parent = tag.split('/')[0]
                    child = tag.split('/')[1]
                    if parent not in parent_children:
                        parent_children[parent] = set()
                    parent_children[parent].add(child)
violations = [p for p, children in parent_children.items() if len(children) > 20]
if violations:
    print(f"Parents with > 20 children: {violations}")
    exit(1)
exit(0)
PYEOF

constraint_primary_tags_max_20_topics.cmd:
cd $PROJECT_ROOT && python3 << 'PYEOF'
import json
with open('prep/superset.k.json') as f:
    data = json.load(f)
primary_tag_counts = {}
for section in data.get('children', {}).values():
    for question in section.get('children', {}).values():
        tags = question.get('metadata', {}).get('tags', '')
        if tags:
            primary_tags = set()
            for tag in tags.split(','):
                tag = tag.strip()
                if tag.count('/') >= 1:
                    parts = tag.split('/')
                    primary_tag = f"{parts[0]}/{parts[1]}"
                    primary_tags.add(primary_tag)
            for pt in primary_tags:
                primary_tag_counts[pt] = primary_tag_counts.get(pt, 0) + 1
violations = {tag: count for tag, count in primary_tag_counts.items() if count > 20}
if violations:
    sorted_v = sorted(violations.items(), key=lambda x: -x[1])
    print(f"Primary tags exceeding 20 topics: {len(violations)}")
    for tag, count in sorted_v[:5]:
        print(f"  {tag}: {count}")
    exit(1)
exit(0)
PYEOF
